  ('elementary-d0d1b9a2-moex-00295', 'elementary-d0d1b9a2', 'elementary-d0d1b9a2-moex-113-426aa0fd', 'sub-elementary-d0d1b9a2-03', NULL, 'single_choice', '下列有關機器設備之支出，有幾項屬於收益支出？①購置新機器  ②原有機器增添可增加生產效率之新', '["經常性維修", "可降低生產不良率之重大維修", "1項", "2項"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:46+00:00", "source_pdf_sha1": "661f3568be1b", "answer_pdf_sha1": "4f7f06df392a", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "508", "s": "0504", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "會計學大意", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "會計"}'::jsonb, NULL),
  ('elementary-d0d1b9a2-moex-00296', 'elementary-d0d1b9a2', 'elementary-d0d1b9a2-moex-113-426aa0fd', 'sub-elementary-d0d1b9a2-03', NULL, 'single_choice', 'X1年1月1日甲公司以一台已使用10年的大型冰箱，與乙公司交換一台九成新的小型冰箱。甲公司大 型冰箱的成本$100,000，殘值$0，耐用年限20年，以直線法計提折舊與成本模式後續衡量。乙公司小型 冰箱的成本$20,000，殘值$0，耐用年限10年，以直線法計提折舊與成本模式後續衡量，公允價值$20,000。 乙公司除交付小型冰箱之外，並支付現金$30,000。若該交換具商業實質，乙公司對所換入大型冰箱的入 帳金額為何？', '["$30,000", "$48,000", "$50,000", "$100,000"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:46+00:00", "source_pdf_sha1": "661f3568be1b", "answer_pdf_sha1": "4f7f06df392a", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "508", "s": "0504", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "會計學大意", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "會計"}'::jsonb, NULL),
  ('elementary-d0d1b9a2-moex-00297', 'elementary-d0d1b9a2', 'elementary-d0d1b9a2-moex-113-426aa0fd', 'sub-elementary-d0d1b9a2-03', NULL, 'single_choice', '甲公司於X3年初購入機器，成本$420,000，估計耐用年限6年，殘值$60,000，以直線法提列折舊。X6年 初，甲公司為提高機器運作效率而加裝馬達，共支出$168,000，機器之耐用年限、殘值均不變。甲公司誤 將X6年機器之相關支出全數認列為當期費用，則此錯誤對X6年度稅前淨利之影響為何？', '["低估$112,000", "低估$132,000", "低估$52,000", "低估$140,000"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:46+00:00", "source_pdf_sha1": "661f3568be1b", "answer_pdf_sha1": "4f7f06df392a", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "508", "s": "0504", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "會計學大意", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "會計"}'::jsonb, NULL),
  ('elementary-d0d1b9a2-moex-00298', 'elementary-d0d1b9a2', 'elementary-d0d1b9a2-moex-113-426aa0fd', 'sub-elementary-d0d1b9a2-03', NULL, 'single_choice', '甲公司於X1年1月1日以$230,000購入機器設備，公司另付安裝測試費用$30,000，估計耐用年限為10 年，殘值為$10,000，採直線法提列折舊與成本模式衡量。由於保養良好，X5年初發現耐用年限可再延長 2年，殘值不變。請問X5年認列的折舊應為多少？（答案四捨五入至元）', '["$25,000", "$20,833", "$20,750", "$18,750"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:46+00:00", "source_pdf_sha1": "661f3568be1b", "answer_pdf_sha1": "4f7f06df392a", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "508", "s": "0504", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "會計學大意", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "會計"}'::jsonb, NULL),
  ('elementary-d0d1b9a2-moex-00299', 'elementary-d0d1b9a2', 'elementary-d0d1b9a2-moex-113-426aa0fd', 'sub-elementary-d0d1b9a2-03', NULL, 'single_choice', '丙公司在X1年初以$20,000,000購入一棟大樓，分類為投資性不動產，以成本模式衡量，耐用20年，殘 值為零。丙公司在X6年1月1日對該大樓認列減損損失$4,500,000，剩餘耐用年限及殘值之估計不變。 在X7年1月1日將該大樓以$18,000,000出售，則出售利益為何？', '["$2,500,000", "$6,500,000", "$7,500,000", "$8,200,000"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:46+00:00", "source_pdf_sha1": "661f3568be1b", "answer_pdf_sha1": "4f7f06df392a", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "508", "s": "0504", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "會計學大意", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "會計"}'::jsonb, NULL),
  ('elementary-d0d1b9a2-moex-00300', 'elementary-d0d1b9a2', 'elementary-d0d1b9a2-moex-113-426aa0fd', 'sub-elementary-d0d1b9a2-03', NULL, 'single_choice', '丙公司原有一自用大樓，自X9年1 月1 日起改變用途為投資性不動產採公允價值模式衡量，供出租使 用。該大樓於改變用途前採成本模式衡量，帳面金額為$4,000,000（包括土地成本$3,000,000、房屋成本 $2,000,000 減累計折舊$1,000,000），於改變用途日該大樓之土地及房屋公允價值分別為$4,000,000 及 $1,500,000，則該用途改變對財務報表的影響（不考慮所得稅之影響），下列敘述何者正確？', '["對淨利無影響", "對其他綜合損益無影響", "對資產無影響", "累計折舊增加"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:46+00:00", "source_pdf_sha1": "661f3568be1b", "answer_pdf_sha1": "4f7f06df392a", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "508", "s": "0504", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "會計學大意", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "會計"}'::jsonb, NULL),
  ('elementary-d0d1b9a2-moex-00301', 'elementary-d0d1b9a2', 'elementary-d0d1b9a2-moex-113-426aa0fd', 'sub-elementary-d0d1b9a2-03', NULL, 'single_choice', '依據國際會計準則第41號「農業」，其所認列之收益與費損不包含下列何者？', '["公允價值減出售成本之變動損益", "產出農產品之公允價值減出售成本", "農業生產成本", "其他綜合損益"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:46+00:00", "source_pdf_sha1": "661f3568be1b", "answer_pdf_sha1": "4f7f06df392a", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "508", "s": "0504", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "會計學大意", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "會計"}'::jsonb, NULL),
  ('elementary-d0d1b9a2-moex-00302', 'elementary-d0d1b9a2', 'elementary-d0d1b9a2-moex-113-426aa0fd', 'sub-elementary-d0d1b9a2-03', NULL, 'single_choice', '甲公司之生物資產衡量採成本模式，帳面金額$1,000,000，X1年12月因寒流來襲造成損傷，其估計之公 允價值為$800,000，處分成本為$50,000，則應認列之減損損失金額為何？', '["$0", "$200,000", "$250,000", "$950,000"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:46+00:00", "source_pdf_sha1": "661f3568be1b", "answer_pdf_sha1": "4f7f06df392a", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "508", "s": "0504", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "會計學大意", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "會計"}'::jsonb, NULL),
