  ('elementary-d0d1b9a2-moex-00304', 'elementary-d0d1b9a2', 'elementary-d0d1b9a2-moex-113-426aa0fd', 'sub-elementary-d0d1b9a2-03', NULL, 'single_choice', '甲公司銷售之商品均有一年之售後免費維修服務，依據經驗售出之產品約有5%會出現瑕疵，平均維修費 用為每個$50。甲公司於 X8 年度中共售出 180,000 個產品，X8 年實際發生$800,000 之維修成本，其中 $500,000為X7年銷售商品之維修。若甲公司於X7年財務報表認列之負債準備金額為$500,000，則X8年 財務報表應認列之負債準備金額為何？', '["$0", "$150,000", "$450,000", "$950,000"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:46+00:00", "source_pdf_sha1": "661f3568be1b", "answer_pdf_sha1": "4f7f06df392a", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "508", "s": "0504", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "會計學大意", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "會計"}'::jsonb, NULL)
